});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const updatedTask = tasksService.updateTaskStatus({ projectId: req.params.projectId, taskId: req.params.taskId, status });
  if (!updatedTask) return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  res.json({ task: updatedTask });
});

export default router;
