    {"path":"src/modules/tasks/service.js","content":"import { randomUUID } from 'node:crypto';
import BadRequestError from '../../lib/errors.js';

const tasks = [];

export const createTask = ({ projectId, title }) => {
  if (!title) throw new BadRequestError('Title is required');
  const id = randomUUID();
  const task = { id, projectId, status: 'todo' };
  tasks.push(task);
  return task;
};

export const updateTaskStatus = ({ projectId, taskId, status }) => {
  const taskIndex = tasks.findIndex(t => t.id === taskId && t.projectId === projectId);
  if (taskIndex === -1) return null;
  tasks[taskIndex].status = status;
  return tasks[taskIndex];
};
